import React, { Component } from "react"
import styled from "styled-components"
import styles from "../styles/styles"
import { Link, graphql } from 'gatsby'

import WebPage from "../components/webPage/WebPage"
import PageArticle from "../components/pageArticle/PageArticle"
import Emoji from "../components/emoji/Emoji"

const ProjectsPage = ({data}) => {

  var projects = data.allMdx.nodes

  projects = projects.map(project => {
    return(
      <Link key={project.id} to={project.fields.slug}>
        <h3>
          {project.frontmatter.title}
        </h3>
      </Link>
    )
  })

  return(
    <WebPage>

      <PageArticle>

        <h1>Projects</h1>

        // {projects}

      </PageArticle>

    </WebPage>
  )
}

export const pageQuery = graphql`
  query projectsQuery {
    allMdx(filter: {fields: {collection: {eq: "projects"}}}, sort: {order: ASC, fields: frontmatter___title}) {
      nodes {
        id
        frontmatter {
          title
        }
        fields {
          slug
        }
      }
    }
  }
`

export default ProjectsPage
